			name: "HWThread->Socket", nativeScope: schema.MetricScopeHWThread,
			requestedScope: schema.MetricScopeSocket, expectOk: true, expectLen: 2, // 2 sockets
			expectAgg: true, expectScope: schema.MetricScopeSocket,
